'use client';
import React, { useState, useEffect } from 'react';
import { Box, Typography, Avatar, Container, Rating } from '@mui/material';
import { FormatQuote } from '@mui/icons-material';
import { motion, AnimatePresence } from 'framer-motion';

const TestimonialSlider = () => {
  const [currentIndex, setCurrentIndex] = useState(0);

  const testimonials = [
    {
      id: 1,
      name: 'Rajesh Kumar',
      role: 'Homeowner, Delhi',
      rating: 5,
      text: 'Installed a 10KW solar system last year. My electricity bills have reduced by 85%! The installation was smooth and the team was very professional. Highly recommended!',
      avatar: '👤',
    },
    {
      id: 2,
      name: 'Priya Sharma',
      role: 'Business Owner, Mumbai',
      rating: 5,
      text: 'We installed solar panels for our factory. The ROI has been excellent and we\'re saving thousands every month. The maintenance service is also top-notch.',
      avatar: '👤',
    },
    {
      id: 3,
      name: 'Amit Patel',
      role: 'Farmer, Gujarat',
      rating: 5,
      text: 'Solar pump has been a game-changer for my farm. No more electricity bills and reliable water supply throughout the year. Best investment I\'ve made!',
      avatar: '👤',
    },
    {
      id: 4,
      name: 'Sunita Reddy',
      role: 'Residential Customer, Bangalore',
      rating: 5,
      text: 'The subsidy assistance team helped me get government benefits easily. The entire process was hassle-free and I\'m now enjoying free electricity!',
      avatar: '👤',
    },
  ];

  useEffect(() => {
    const interval = setInterval(() => {
      setCurrentIndex((prev) => (prev + 1) % testimonials.length);
    }, 5000);
    return () => clearInterval(interval);
  }, [testimonials.length]);

  return (
    <Box
      sx={{
        py: 8,
        bgcolor: 'background.default',
        position: 'relative',
      }}
    >
      <Container maxWidth="md">
        <Typography
          variant="h2"
          sx={{
            textAlign: 'center',
            fontWeight: 800,
            mb: 6,
            color: 'text.primary',
          }}
        >
          What Our Customers Say
        </Typography>

        <Box
          sx={{
            position: 'relative',
            minHeight: '300px',
            display: 'flex',
            alignItems: 'center',
            justifyContent: 'center',
          }}
        >
          <AnimatePresence mode="wait">
            <motion.div
              key={currentIndex}
              initial={{ opacity: 0, x: 50 }}
              animate={{ opacity: 1, x: 0 }}
              exit={{ opacity: 0, x: -50 }}
              transition={{ duration: 0.5 }}
              style={{ width: '100%' }}
            >
              <Box
                sx={{
                  textAlign: 'center',
                  p: 4,
                  bgcolor: 'background.paper',
                  borderRadius: 4,
                  boxShadow: 3,
                  position: 'relative',
                }}
              >
                <FormatQuote
                  sx={{
                    fontSize: 60,
                    color: 'primary.main',
                    opacity: 0.2,
                    position: 'absolute',
                    top: 20,
                    left: 20,
                  }}
                />
                <Rating
                  value={testimonials[currentIndex].rating}
                  readOnly
                  sx={{ mb: 3 }}
                />
                <Typography
                  variant="h6"
                  sx={{
                    fontStyle: 'italic',
                    mb: 4,
                    color: 'text.primary',
                    lineHeight: 1.8,
                    position: 'relative',
                    zIndex: 1,
                  }}
                >
                  "{testimonials[currentIndex].text}"
                </Typography>
                <Box sx={{ display: 'flex', alignItems: 'center', justifyContent: 'center', gap: 2 }}>
                  <Avatar
                    sx={{
                      bgcolor: 'primary.main',
                      width: 60,
                      height: 60,
                      fontSize: '2rem',
                    }}
                  >
                    {testimonials[currentIndex].avatar}
                  </Avatar>
                  <Box>
                    <Typography variant="h6" sx={{ fontWeight: 700 }}>
                      {testimonials[currentIndex].name}
                    </Typography>
                    <Typography variant="body2" color="text.secondary">
                      {testimonials[currentIndex].role}
                    </Typography>
                  </Box>
                </Box>
              </Box>
            </motion.div>
          </AnimatePresence>
        </Box>

        {/* Dots Indicator */}
        <Box
          sx={{
            display: 'flex',
            justifyContent: 'center',
            gap: 1,
            mt: 4,
          }}
        >
          {testimonials.map((_, index) => (
            <Box
              key={index}
              onClick={() => setCurrentIndex(index)}
              sx={{
                width: currentIndex === index ? 32 : 12,
                height: 12,
                borderRadius: 6,
                bgcolor: currentIndex === index ? 'primary.main' : 'grey.300',
                cursor: 'pointer',
                transition: 'all 0.3s ease',
              }}
            />
          ))}
        </Box>
      </Container>
    </Box>
  );
};

export default TestimonialSlider;

