'use client';
import React from 'react';
import { Container, Box, Typography, Button } from '@mui/material';
import { useRouter } from 'next/navigation';
import { motion } from 'framer-motion';
import HeroBanner from '@/components/HeroBanner/HeroBanner';
import SolarProductsGrid from '@/components/SolarProductsGrid/SolarProductsGrid';
import ServicesGrid from '@/components/ServicesGrid/ServicesGrid';
import TestimonialSlider from '@/components/TestimonialSlider/TestimonialSlider';
import FAQAccordion from '@/components/FAQAccordion/FAQAccordion';
import AnimatedCounter from '@/components/AnimatedCounter/AnimatedCounter';

const Home = () => {
  const router = useRouter();

  return (
    <Box>
      {/* Hero Section */}
      <HeroBanner />

      {/* Products Section */}
      <Container maxWidth="xl" sx={{ py: 8 }}>
        <Box sx={{ textAlign: 'center', mb: 6 }}>
          <Typography
            variant="h2"
            sx={{
              fontWeight: 800,
              mb: 2,
              background: 'linear-gradient(135deg, #FFA500, #2B7A0B)',
              WebkitBackgroundClip: 'text',
              WebkitTextFillColor: 'transparent',
            }}
          >
            Our Solar Products
          </Typography>
          <Typography variant="h6" color="text.secondary" sx={{ maxWidth: 600, mx: 'auto' }}>
            Discover our comprehensive range of solar energy solutions designed to meet all your
            energy needs
          </Typography>
        </Box>
        <SolarProductsGrid />
      </Container>

      {/* Services Section */}
      <Box sx={{ bgcolor: 'background.default', py: 8 }}>
        <Container maxWidth="xl">
          <Box sx={{ textAlign: 'center', mb: 6 }}>
            <Typography variant="h2" sx={{ fontWeight: 800, mb: 2 }}>
              Our Services
            </Typography>
            <Typography variant="h6" color="text.secondary" sx={{ maxWidth: 600, mx: 'auto' }}>
              End-to-end solar solutions from installation to maintenance
            </Typography>
          </Box>
          <ServicesGrid />
        </Container>
      </Box>

      {/* Stats Section */}
      <Container maxWidth="xl" sx={{ py: 8 }}>
        <Box
          sx={{
            bgcolor: 'primary.main',
            borderRadius: 4,
            p: 6,
            textAlign: 'center',
            color: 'white',
          }}
        >
          <Typography variant="h3" sx={{ fontWeight: 800, mb: 6 }}>
            Our Achievements
          </Typography>
          <Box
            sx={{
              display: 'grid',
              gridTemplateColumns: { xs: '1fr', md: 'repeat(3, 1fr)' },
              gap: 4,
            }}
          >
            <motion.div
              initial={{ opacity: 0, y: 20 }}
              whileInView={{ opacity: 1, y: 0 }}
              viewport={{ once: true }}
              transition={{ duration: 0.5 }}
            >
              <AnimatedCounter value={50} suffix="+" delay={0.2} />
              <Typography variant="h6" sx={{ mt: 2, opacity: 0.9 }}>
                Happy Customers
              </Typography>
            </motion.div>
            <motion.div
              initial={{ opacity: 0, y: 20 }}
              whileInView={{ opacity: 1, y: 0 }}
              viewport={{ once: true }}
              transition={{ duration: 0.5, delay: 0.1 }}
            >
              <AnimatedCounter value={500} suffix="KW+" delay={0.4} />
              <Typography variant="h6" sx={{ mt: 2, opacity: 0.9 }}>
                Installed
              </Typography>
            </motion.div>
            <motion.div
              initial={{ opacity: 0, y: 20 }}
              whileInView={{ opacity: 1, y: 0 }}
              viewport={{ once: true }}
              transition={{ duration: 0.5, delay: 0.2 }}
            >
              <AnimatedCounter value={25} suffix="+" delay={0.6} />
              <Typography variant="h6" sx={{ mt: 2, opacity: 0.9 }}>
                Projects Done
              </Typography>
            </motion.div>
          </Box>
        </Box>
      </Container>

      {/* Testimonials */}
      <TestimonialSlider />

      {/* CTA Section */}
      <Container maxWidth="xl" sx={{ py: 8 }}>
        <Box
          sx={{
            bgcolor: 'background.paper',
            borderRadius: 4,
            p: 6,
            textAlign: 'center',
            boxShadow: 3,
          }}
        >
          <Typography variant="h2" sx={{ fontWeight: 800, mb: 2 }}>
            Ready to Go Solar?
          </Typography>
          <Typography variant="h6" color="text.secondary" sx={{ mb: 4, maxWidth: 600, mx: 'auto' }}>
            Get a free quote today and start saving on your electricity bills
          </Typography>
          <Button
            variant="contained"
            size="large"
            onClick={() => router.push('/contact')}
            sx={{ px: 6, py: 1.5, fontSize: '1.1rem' }}
          >
            Get Free Quote
          </Button>
        </Box>
      </Container>

      {/* FAQ Section */}
      <FAQAccordion />
    </Box>
  );
};

export default Home;

