'use client';
import React from 'react';
import { Grid, Card, CardContent, CardMedia, Typography, Box, Button } from '@mui/material';
import { ArrowForward } from '@mui/icons-material';
import { motion } from 'framer-motion';
import { useRouter } from 'next/navigation';

interface SolarProductsGridProps {
  products?: any[];
  showViewAll?: boolean;
}

const SolarProductsGrid = ({ products, showViewAll = true }: SolarProductsGridProps) => {
  const router = useRouter();

  const defaultProducts = [
    {
      id: 1,
      title: 'Solar Panels',
      description: 'High-efficiency monocrystalline and polycrystalline solar panels for maximum energy output.',
      icon: '☀️',
      image: 'https://images.unsplash.com/photo-1509391366360-2e959784a276?w=400',
    },
    {
      id: 2,
      title: 'Solar Rooftop Systems',
      description: 'Complete rooftop solar solutions for residential and commercial buildings.',
      icon: '🏠',
      image: 'https://images.unsplash.com/photo-1464226184884-fa280b87c399?w=400',
    },
    {
      id: 3,
      title: 'Solar Water Heater',
      description: 'Eco-friendly solar water heating systems to reduce electricity consumption.',
      icon: '🔥',
      image: 'https://images.unsplash.com/photo-1558618666-fcd25c85cd64?w=400',
    },
    {
      id: 4,
      title: 'Solar Pump',
      description: 'Solar-powered water pumps for agriculture and irrigation needs.',
      icon: '💧',
      image: 'https://images.unsplash.com/photo-1558618047-3c8c76ca7d13?w=400',
    },
    {
      id: 5,
      title: 'Inverters & Batteries',
      description: 'High-quality inverters and battery storage solutions for reliable power backup.',
      icon: '🔋',
      image: 'https://images.unsplash.com/photo-1605647540924-852290d6e597?w=400',
    },
    {
      id: 6,
      title: 'EPC Services',
      description: 'End-to-end Engineering, Procurement, and Construction services for solar projects.',
      icon: '⚙️',
      image: 'https://images.unsplash.com/photo-1581091226825-a6a2a5aee158?w=400',
    },
  ];

  const displayProducts = products || defaultProducts;

  return (
    <Box sx={{ py: 8 }}>
      <Grid container spacing={4}>
        {displayProducts.map((product, index) => (
          <Grid item xs={12} sm={6} md={4} key={product.id || index}>
            <motion.div
              initial={{ opacity: 0, y: 30 }}
              whileInView={{ opacity: 1, y: 0 }}
              viewport={{ once: true }}
              transition={{ duration: 0.5, delay: index * 0.1 }}
            >
              <Card
                sx={{
                  height: '100%',
                  display: 'flex',
                  flexDirection: 'column',
                  cursor: 'pointer',
                  '&:hover': {
                    '& .product-icon': {
                      transform: 'scale(1.1) rotate(5deg)',
                    },
                  },
                }}
                onClick={() => router.push('/products')}
              >
                <CardMedia
                  component="div"
                  sx={{
                    height: 200,
                    background: `linear-gradient(135deg, ${product.color || '#FFA500'}20, ${product.color || '#2B7A0B'}20)`,
                    display: 'flex',
                    alignItems: 'center',
                    justifyContent: 'center',
                    position: 'relative',
                    overflow: 'hidden',
                  }}
                >
                  <Box
                    className="product-icon"
                    sx={{
                      fontSize: '4rem',
                      transition: 'transform 0.3s ease',
                    }}
                  >
                    {product.icon}
                  </Box>
                </CardMedia>
                <CardContent sx={{ flexGrow: 1 }}>
                  <Typography variant="h5" sx={{ fontWeight: 700, mb: 1 }}>
                    {product.title}
                  </Typography>
                  <Typography variant="body2" color="text.secondary" sx={{ mb: 2 }}>
                    {product.description}
                  </Typography>
                  <Button
                    endIcon={<ArrowForward />}
                    sx={{
                      color: 'primary.main',
                      fontWeight: 600,
                      '&:hover': {
                        transform: 'translateX(4px)',
                      },
                      transition: 'transform 0.3s ease',
                    }}
                  >
                    Learn More
                  </Button>
                </CardContent>
              </Card>
            </motion.div>
          </Grid>
        ))}
      </Grid>
      {showViewAll && (
        <Box sx={{ textAlign: 'center', mt: 6 }}>
          <Button
            variant="contained"
            size="large"
            onClick={() => router.push('/products')}
            sx={{ px: 4 }}
          >
            View All Products
          </Button>
        </Box>
      )}
    </Box>
  );
};

export default SolarProductsGrid;

